// Extract device ID from topic
var parts = msg.topic.split('/');
var deviceId = parts[1] || 'unknown';

// Find first numeric value (flat or nested)
var metric = '';
var value = 0;
for (var key in msg.payload) {
    if (typeof msg.payload[key] === 'number') {
        metric = key;
        value = msg.payload[key];
        break;
    }
    if (typeof msg.payload[key] === 'object') {
        for (var subkey in msg.payload[key]) {
            if (typeof msg.payload[key][subkey] === 'number') {
                metric = subkey;
                value = msg.payload[key][subkey];
                break;
            }
        }
        if (metric) break;
    }
}

// Store in flow context (latest message cache)
var latest = flow.get('latest') || {};
latest[deviceId] = {
    device_id: deviceId,
    metric: metric,
    value: value,
    timestamp: Date.now(),
    source_proto: 'mqtt'
};
flow.set('latest', latest);

// Count messages
var count = flow.get('msg_count') || 0;
flow.set('msg_count', count + 1);

return msg;

var deviceId = msg.req.params.deviceId;
var latest = flow.get('latest') || {};
var data = latest[deviceId];
if (!data) {
    msg.statusCode = 404;
    msg.payload = { error: 'no data for device' };
} else {
    msg.payload = data;
}
return msg;

var latest = flow.get('latest') || {};
var deviceCount = Object.keys(latest).length;
var msgCount = flow.get('msg_count') || 0;
var mem = process.memoryUsage();
msg.payload = {
    uptime_seconds: Math.floor(process.uptime()),
    device_count: deviceCount,
    messages_processed: msgCount,
    memory: {
        heap_alloc_mb: Math.round(mem.heapUsed / 1024 / 1024 * 100) / 100,
        heap_total_mb: Math.round(mem.heapTotal / 1024 / 1024 * 100) / 100,
        rss_mb: Math.round(mem.rss / 1024 / 1024 * 100) / 100,
        external_mb: Math.round(mem.external / 1024 / 1024 * 100) / 100
    },
    runtime: {
        node_version: process.version,
        platform: process.platform
    }
};
return msg;

var deviceId = msg.req.params.deviceId;
var latest = flow.get('latest') || {};
latest[deviceId] = {
    device_id: deviceId,
    metric: msg.payload.metric || '',
    value: msg.payload.value || 0,
    unit: msg.payload.unit || '',
    timestamp: Date.now(),
    source_proto: 'http'
};
flow.set('latest', latest);
var count = flow.get('msg_count') || 0;
flow.set('msg_count', count + 1);
msg.payload = { message_id: Date.now().toString(16), status: 'accepted' };
msg.statusCode = 202;
return msg;
